+export type DurationObservation = { duration: number, recordedAt: number }
+
+export function smoothDuration(observations: DurationObservation[], smoothing: 'latest' | 'average' | 'p95' | 'median'): number {
+  if (!observations.length) return 0
+  if (smoothing === 'latest') return observations.reduce((latest, value) => value.recordedAt > latest.recordedAt ? value : latest).duration
+  const values = observations.map(value => value.duration).sort((a, b) => a - b)
